class Solution:
    def countWords(self, words1, words2):
        count1 = {}
        for w in words1:
            count1[w] = count1.get(w, 0) + 1
        count2 = {}
        for w in words2:
            count2[w] = count2.get(w, 0) + 1
        total = 0
        for w in set(words1) | set(words2):
            if count1.get(w, 0) == 1 and count2.get(w, 0) == 1:
                total += 1
        return total

