from collections import Counter
class Solution:
    def countWords(self, words1, words2):
        c1 = Counter(words1)
        c2 = Counter(words2)
        if len(c1) <= len(c2):
            smaller, other = c1, c2
        else:
            smaller, other = c2, c1
        total = 0
        for word, freq in smaller.items():
            if freq == 1 and other.get(word, 0) == 1:
                total += 1
        return total

