var countWords = function(words1, words2) {
    const count = (arr) => {
        const m = new Map();
        for (const w of arr) m.set(w, (m.get(w) || 0) + 1);
        return m;
    };
    const c1 = count(words1);
    const c2 = count(words2);
    const [smaller, other] = c1.size <= c2.size ? [c1, c2] : [c2, c1];
    let total = 0;
    for (const [word, freq] of smaller) {
        if (freq === 1 && (other.get(word) || 0) === 1) total++;
    }
    return total;
};
